# PHASE 1 VALIDATION — manually written, not generated by testgen.py.
# Do not delete: this file survives codegen regeneration.
#
# Run: pytest test_phase1_protocol_edge_cases.py -v --can-interface=simulator
#
# Covers protocol correctness gaps not exercised by testgen output:
#   A. DTC status mask filtering (sub=0x01 and sub=0x02)
#   B. Session/security state machine integrity (downgrade, ECUReset)
#   C. TesterPresent sub-function edge cases (0xFF, 0x7F, single-byte)
#   D. ReadDataByIdentifier: multi-DID, malformed requests
#   E. WriteDataByIdentifier: happy-path, wrong-length, session/security gates
#   F. ISO-TP explicit: large payload (17-byte VIN) multi-frame round-trip
#   G. ClearDiagnosticInformation: positive response, idempotent re-read

from __future__ import annotations

import struct
import pytest

from conftest import (
    IsoTpTransport,
    SESSION_DEFAULT, SESSION_EXTENDED, SESSION_PROGRAMMING,
    SID_DIAGNOSTIC_SESSION_CONTROL, SID_ECU_RESET, SID_READ_DTC_INFO,
    SID_READ_DATA_BY_ID, SID_WRITE_DATA_BY_ID, SID_SECURITY_ACCESS,
    SID_TESTER_PRESENT, SID_ROUTINE_CONTROL, SID_NEGATIVE_RESPONSE,
    POSITIVE_RESPONSE_OFFSET,
    NRC_INCORRECT_MSG_LEN, NRC_SUB_FUNCTION_NOT_SUPPORTED,
    NRC_REQUEST_OUT_OF_RANGE, NRC_SECURITY_ACCESS_DENIED,
    NRC_SERVICE_NOT_SUPPORTED_IN_SESSION, NRC_INVALID_KEY,
    NRC_CONDITIONS_NOT_CORRECT,
    ALGO_KEY_LEN,
    _EcuSimulator,
)

# ---------------------------------------------------------------------------
# Helpers (mirrors test_services.py, duplicated to keep this file self-contained)
# ---------------------------------------------------------------------------

def _session(bus: IsoTpTransport, s: int) -> None:
    pdu = bus.request(bytes([SID_DIAGNOSTIC_SESSION_CONTROL, s & 0x7F]))
    assert pdu is not None
    assert pdu[0] == (SID_DIAGNOSTIC_SESSION_CONTROL + POSITIVE_RESPONSE_OFFSET), (
        f"Session 0x{s:02X} switch failed: {pdu.hex(' ')}"
    )


def _unlock(bus: IsoTpTransport, level: int, aes_keys: dict) -> None:
    seed_sub = (level * 2) - 1
    key_sub  = level * 2
    seed_pdu = bus.request(bytes([SID_SECURITY_ACCESS, seed_sub]))
    assert seed_pdu is not None
    assert seed_pdu[0] == (SID_SECURITY_ACCESS + POSITIVE_RESPONSE_OFFSET)
    seed = seed_pdu[2:]
    sim  = _EcuSimulator()
    key  = sim._derive_key(seed, level)
    provided = aes_keys.get(level)
    if provided and provided != sim._LEVEL_KEYS.get(level):
        key = sim._cmac(provided, seed)[:4]
    key_pdu = bus.request(bytes([SID_SECURITY_ACCESS, key_sub]) + key)
    assert key_pdu is not None
    assert key_pdu[0] == (SID_SECURITY_ACCESS + POSITIVE_RESPONSE_OFFSET), (
        f"Unlock level {level} failed: {key_pdu.hex(' ')}"
    )


# ===========================================================================
# A. DTC status mask filtering
#
# ISO 14229-1 §11.3: the ECU must filter DTCs by (statusByte & mask).
# In the initial simulator state all DTCs have status 0x00.
# With mask=0xFF: 0x00 & 0xFF = 0x00 (no match) → empty DTC list, count = 0.
# With mask=0x00: any_status & 0x00 = 0x00 (no match) → always empty.
#
# Known bug: the inline simulator (_inline_handle) returns all DTCs regardless
# of the mask, both for sub=0x01 (count) and sub=0x02 (list).
# The docker ECU sim (sim.py) filters correctly.
# ===========================================================================

class TestDTCStatusMaskFiltering:
    """
    ISO 14229-1 §11.3.2 / §11.3.5 — DTC status mask must be applied.
    """

    def test_sub02_mask_0xff_empty_when_all_status_zero(
        self, uds_bus: IsoTpTransport
    ) -> None:
        """
        sub=0x02, mask=0xFF: with all DTC statuses at 0x00,
        (0x00 & 0xFF) = 0x00 → no match → response must contain 0 DTC entries.
        Response format: [0x59, 0x02, availMask] — exactly 3 bytes.
        """
        pdu = uds_bus.request(bytes([SID_READ_DTC_INFO, 0x02, 0xFF]))
        assert pdu is not None
        assert pdu[0] == (SID_READ_DTC_INFO + POSITIVE_RESPONSE_OFFSET), (
            f"Expected positive response, got NRC: {pdu.hex(' ')}"
        )
        assert pdu[1] == 0x02
        dtc_section = pdu[3:]
        assert len(dtc_section) == 0, (
            f"DTC mask=0xFF with all-zero status: expected 0 DTC entries, "
            f"got {len(dtc_section) // 4} entries: {pdu.hex(' ')}"
        )

    def test_sub02_mask_0x00_always_empty(
        self, uds_bus: IsoTpTransport
    ) -> None:
        """
        sub=0x02, mask=0x00: (any_status & 0x00) = 0x00 always → no match.
        Must return 0 DTC entries regardless of DTC state.
        """
        pdu = uds_bus.request(bytes([SID_READ_DTC_INFO, 0x02, 0x00]))
        assert pdu is not None
        assert pdu[0] == (SID_READ_DTC_INFO + POSITIVE_RESPONSE_OFFSET)
        dtc_section = pdu[3:]
        assert len(dtc_section) == 0, (
            f"DTC mask=0x00: expected 0 DTC entries always, "
            f"got {len(dtc_section) // 4} entries: {pdu.hex(' ')}"
        )

    def test_sub01_count_zero_when_all_status_zero(
        self, uds_bus: IsoTpTransport
    ) -> None:
        """
        sub=0x01, mask=0xFF: count of matching DTCs must be 0 when all statuses
        are 0x00. Response: [0x59, 0x01, availMask, formatID, count_hi, count_lo].
        """
        pdu = uds_bus.request(bytes([SID_READ_DTC_INFO, 0x01, 0xFF]))
        assert pdu is not None
        assert pdu[0] == (SID_READ_DTC_INFO + POSITIVE_RESPONSE_OFFSET)
        assert len(pdu) >= 6
        count = struct.unpack(">H", pdu[4:6])[0]
        assert count == 0, (
            f"sub=0x01 mask=0xFF with all-zero DTC statuses: "
            f"expected count=0, got count={count}"
        )

    def test_sub01_count_zero_mask_0x00(
        self, uds_bus: IsoTpTransport
    ) -> None:
        """
        sub=0x01, mask=0x00: count must always be 0 (nothing can match).
        """
        pdu = uds_bus.request(bytes([SID_READ_DTC_INFO, 0x01, 0x00]))
        assert pdu is not None
        assert pdu[0] == (SID_READ_DTC_INFO + POSITIVE_RESPONSE_OFFSET)
        assert len(pdu) >= 6
        count = struct.unpack(">H", pdu[4:6])[0]
        assert count == 0, (
            f"sub=0x01 mask=0x00: expected count=0 always, got {count}"
        )

    def test_sub02_unknown_subfunction_0x10_rejected(
        self, uds_bus: IsoTpTransport
    ) -> None:
        """Sub=0x10 is not defined — must return NRC 0x12."""
        pdu = uds_bus.request(bytes([SID_READ_DTC_INFO, 0x10, 0xFF]))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[1] == SID_READ_DTC_INFO
        assert pdu[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED, (
            f"Expected NRC 0x12, got 0x{pdu[2]:02X}"
        )

    def test_sub02_too_short_pdu_rejected(
        self, uds_bus: IsoTpTransport
    ) -> None:
        """[0x19] with no sub-function must return NRC 0x13."""
        pdu = uds_bus.request(bytes([SID_READ_DTC_INFO]))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_INCORRECT_MSG_LEN


# ===========================================================================
# B. Session / security state machine integrity
# ===========================================================================

class TestStateMachineIntegrity:
    """
    Security unlock must not survive session transitions or ECUReset.
    ISO 14229-1 §10.4: security access is cleared on session change.
    """

    def test_security_cleared_on_session_downgrade(
        self, uds_bus: IsoTpTransport, aes_keys: dict
    ) -> None:
        """
        Unlock in Extended → downgrade to Default → re-enter Extended →
        secured DID write must fail with NRC 0x33 (not carry-over the unlock).
        """
        _session(uds_bus, SESSION_EXTENDED)
        _unlock(uds_bus, 1, aes_keys)

        # Downgrade resets security
        _session(uds_bus, SESSION_DEFAULT)
        _session(uds_bus, SESSION_EXTENDED)

        # F187 write needs sec level 1 — should now be locked again
        pdu = uds_bus.request(
            bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x87]) + bytes([0x41] * 11)
        )
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE, (
            "Secured DID write must fail after session downgrade clears security"
        )
        assert pdu[2] == NRC_SECURITY_ACCESS_DENIED, (
            f"Expected NRC 0x33 (securityAccessDenied), got 0x{pdu[2]:02X}"
        )

    def test_security_cleared_on_ecu_reset(
        self, uds_bus: IsoTpTransport, aes_keys: dict
    ) -> None:
        """
        Unlock in Extended → ECUReset → re-enter Extended →
        secured DID write must fail with NRC 0x33.
        """
        _session(uds_bus, SESSION_EXTENDED)
        _unlock(uds_bus, 1, aes_keys)

        uds_bus.request(bytes([SID_ECU_RESET, 0x01]))   # hard reset

        # After reset, state should be DEFAULT + locked
        _session(uds_bus, SESSION_EXTENDED)
        pdu = uds_bus.request(
            bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x87]) + bytes([0x41] * 11)
        )
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_SECURITY_ACCESS_DENIED, (
            f"Expected NRC 0x33 after ECUReset, got 0x{pdu[2]:02X}"
        )

    def test_unlock_persists_within_same_session(
        self, uds_bus: IsoTpTransport, aes_keys: dict
    ) -> None:
        """
        A single unlock must cover multiple subsequent secured operations
        within the same session (no re-unlock required per operation).
        """
        _session(uds_bus, SESSION_EXTENDED)
        _unlock(uds_bus, 1, aes_keys)

        # First write
        pdu1 = uds_bus.request(
            bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x87]) + bytes([0x41] * 11)
        )
        assert pdu1 is not None and pdu1[0] == 0x6E, (
            f"First secured write failed: {pdu1.hex(' ') if pdu1 else 'None'}"
        )

        # Second write (no re-unlock)
        pdu2 = uds_bus.request(
            bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x87]) + bytes([0x42] * 11)
        )
        assert pdu2 is not None and pdu2[0] == 0x6E, (
            "Second secured write failed — unlock must persist within session"
        )

    def test_session_change_also_clears_pending_seed(
        self, uds_bus: IsoTpTransport
    ) -> None:
        """
        Requesting a seed then changing session must invalidate the pending seed.
        Subsequent sendKey (even with correct key) must fail with NRC 0x24.
        """
        _session(uds_bus, SESSION_EXTENDED)
        uds_bus.request(bytes([SID_SECURITY_ACCESS, 0x01]))   # request seed

        # Change session (invalidates pending seed)
        _session(uds_bus, SESSION_DEFAULT)
        _session(uds_bus, SESSION_EXTENDED)

        # Attempt sendKey with all-zeros — must fail (no pending seed)
        pdu = uds_bus.request(bytes([SID_SECURITY_ACCESS, 0x02]) + bytes(ALGO_KEY_LEN))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] in (NRC_CONDITIONS_NOT_CORRECT, 0x24), (
            f"Expected NRC 0x22 or 0x24 after seed invalidated by session change, "
            f"got 0x{pdu[2]:02X}"
        )


# ===========================================================================
# C. TesterPresent sub-function edge cases
# ===========================================================================

class TestTesterPresentEdgeCases:
    """
    ISO 14229-1 §9.9: only sub-function 0x00 (and 0x80 suppress variant) is valid.
    Any other sub-function value must return NRC 0x12.
    """

    def test_sub_0xff_rejected(self, uds_bus: IsoTpTransport) -> None:
        """
        [0x3E, 0xFF]: (0xFF & 0x7F) = 0x7F ≠ 0x00 → NRC 0x12.
        Also tests the suppress-bit-ignored-when-subFn-invalid rule.
        """
        pdu = uds_bus.request(bytes([SID_TESTER_PRESENT, 0xFF]))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[1] == SID_TESTER_PRESENT
        assert pdu[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED, (
            f"[0x3E, 0xFF] must return NRC 0x12, got 0x{pdu[2]:02X}"
        )

    def test_sub_0x7f_rejected(self, uds_bus: IsoTpTransport) -> None:
        """
        [0x3E, 0x7F]: (0x7F & 0x7F) = 0x7F ≠ 0x00 → NRC 0x12.
        0x7F is the suppress-bit-clear maximum non-zero sub-function.
        """
        pdu = uds_bus.request(bytes([SID_TESTER_PRESENT, 0x7F]))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED, (
            f"[0x3E, 0x7F] must return NRC 0x12, got 0x{pdu[2]:02X}"
        )

    def test_sub_0x02_rejected(self, uds_bus: IsoTpTransport) -> None:
        """[0x3E, 0x02]: sub-function 0x02 is not valid → NRC 0x12."""
        pdu = uds_bus.request(bytes([SID_TESTER_PRESENT, 0x02]))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED

    def test_single_byte_pdu_rejected(self, uds_bus: IsoTpTransport) -> None:
        """[0x3E] only (no sub-function byte) → NRC 0x13 (incorrectMessageLength)."""
        pdu = uds_bus.request(bytes([SID_TESTER_PRESENT]))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_INCORRECT_MSG_LEN, (
            f"Single-byte TesterPresent must return NRC 0x13, got 0x{pdu[2]:02X}"
        )

    def test_suppress_bit_in_extended_session(self, uds_bus: IsoTpTransport) -> None:
        """[0x3E, 0x80] in Extended Session must suppress the positive response."""
        _session(uds_bus, SESSION_EXTENDED)
        pdu = uds_bus.request(bytes([SID_TESTER_PRESENT, 0x80]))
        assert pdu is None, (
            "TesterPresent 0x80 in Extended Session must suppress response"
        )

    def test_suppress_plus_invalid_subfn_0x81_rejected(
        self, uds_bus: IsoTpTransport
    ) -> None:
        """
        [0x3E, 0x81]: (0x81 & 0x7F) = 0x01 ≠ 0x00 → NRC 0x12.
        Suppress bit must not be applied when the sub-function itself is invalid.
        """
        pdu = uds_bus.request(bytes([SID_TESTER_PRESENT, 0x81]))
        assert pdu is not None, (
            "[0x3E, 0x81]: invalid sub-function — NRC must be returned, "
            "suppress bit must NOT hide the error"
        )
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED


# ===========================================================================
# D. ReadDataByIdentifier edge cases
# ===========================================================================

class TestReadDataByIdentifierEdgeCases:
    """Multi-DID requests, malformed requests, response format validation."""

    def test_multi_did_f190_and_f18c(self, uds_bus: IsoTpTransport) -> None:
        """
        Read VIN (0xF190, 17 bytes) + ECU Serial (0xF18C, 4 bytes) in one request.
        Response: [0x62, 0xF1, 0x90, <17 bytes>, 0xF1, 0x8C, <4 bytes>] = 26 bytes.
        Multi-frame response (26 bytes > 7 SF limit).
        """
        pdu = uds_bus.request(bytes([SID_READ_DATA_BY_ID, 0xF1, 0x90, 0xF1, 0x8C]))
        assert pdu is not None
        assert pdu[0] == (SID_READ_DATA_BY_ID + POSITIVE_RESPONSE_OFFSET), (
            f"Multi-DID read failed: {pdu.hex(' ')}"
        )
        expected_len = 1 + (2 + 17) + (2 + 4)   # RSID + (DID+data) × 2
        assert len(pdu) == expected_len, (
            f"Multi-DID response length: expected {expected_len}, got {len(pdu)}"
        )
        assert pdu[1:3] == bytes([0xF1, 0x90]), "VIN DID echo wrong"
        assert pdu[20:22] == bytes([0xF1, 0x8C]), "Serial DID echo wrong"

    def test_single_byte_request_rejected(self, uds_bus: IsoTpTransport) -> None:
        """[0x22] only — no DID bytes → NRC 0x13."""
        pdu = uds_bus.request(bytes([SID_READ_DATA_BY_ID]))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_INCORRECT_MSG_LEN

    def test_incomplete_did_bytes_rejected(self, uds_bus: IsoTpTransport) -> None:
        """
        [0x22, 0xF1, 0x90, 0xF1]: incomplete second DID (3 DID bytes, not even).
        (len(pdu) - 1) = 3 which is odd → NRC 0x13.
        """
        pdu = uds_bus.request(bytes([SID_READ_DATA_BY_ID, 0xF1, 0x90, 0xF1]))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_INCORRECT_MSG_LEN, (
            f"Incomplete DID bytes must return NRC 0x13, got 0x{pdu[2]:02X}"
        )

    def test_mixed_valid_invalid_did_rejected(self, uds_bus: IsoTpTransport) -> None:
        """
        Multi-DID with one valid (0xF190) and one unknown (0x0001).
        ECU must reject the whole request with NRC 0x31 (first unknown DID).
        """
        pdu = uds_bus.request(bytes([SID_READ_DATA_BY_ID, 0xF1, 0x90, 0x00, 0x01]))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_REQUEST_OUT_OF_RANGE


# ===========================================================================
# E. WriteDataByIdentifier correctness
# ===========================================================================

class TestWriteDataByIdentifierEdgeCases:
    """
    DID 0xF187 (VehicleManufacturerSparePartNumber): 11 bytes, write, extended+sec1.
    DID 0xF190 (VIN): read-only.
    """

    def test_write_to_read_only_did_f190_rejected(
        self, uds_bus: IsoTpTransport
    ) -> None:
        """0xF190 (VIN) is read-only — WDBI must return NRC 0x31."""
        pdu = uds_bus.request(
            bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x90]) + bytes([0x41] * 17)
        )
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_REQUEST_OUT_OF_RANGE, (
            f"Write to read-only DID must return NRC 0x31, got 0x{pdu[2]:02X}"
        )

    def test_wdbi_session_gate_nrc(self, uds_bus: IsoTpTransport) -> None:
        """
        DID 0xF187 requires extended session. Writing in Default must be rejected.
        ISO 14229-1 ASIL-B chain step 2 → NRC 0x7F (serviceNotSupportedInActiveSession).
        Inline simulator historically returns NRC 0x31 — this test verifies correctness.
        """
        pdu = uds_bus.request(
            bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x87]) + bytes([0x41] * 11)
        )
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_SERVICE_NOT_SUPPORTED_IN_SESSION, (
            f"WDBI session gate must return NRC 0x7F per ASIL-B chain step 2, "
            f"got 0x{pdu[2]:02X} (0x31 = requestOutOfRange is incorrect here)"
        )

    def test_wdbi_security_gate_nrc(self, uds_bus: IsoTpTransport) -> None:
        """
        DID 0xF187 in Extended Session without unlock → NRC 0x33.
        """
        _session(uds_bus, SESSION_EXTENDED)
        pdu = uds_bus.request(
            bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x87]) + bytes([0x41] * 11)
        )
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_SECURITY_ACCESS_DENIED

    def test_wdbi_happy_path_f187(
        self, uds_bus: IsoTpTransport, aes_keys: dict
    ) -> None:
        """
        Full happy path: Extended Session + Level 1 unlock + write 11 bytes.
        Response: [0x6E, 0xF1, 0x87].
        """
        _session(uds_bus, SESSION_EXTENDED)
        _unlock(uds_bus, 1, aes_keys)
        pdu = uds_bus.request(
            bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x87]) + bytes([0x58] * 11)
        )
        assert pdu is not None
        assert pdu[0] == (SID_WRITE_DATA_BY_ID + POSITIVE_RESPONSE_OFFSET), (
            f"WDBI happy path failed: {pdu.hex(' ')}"
        )
        assert pdu[1:3] == bytes([0xF1, 0x87]), "DID echo in positive response wrong"

    def test_wdbi_wrong_data_length_short(
        self, uds_bus: IsoTpTransport, aes_keys: dict
    ) -> None:
        """
        DID 0xF187 expects 11 bytes — sending 5 must return NRC 0x13.
        """
        _session(uds_bus, SESSION_EXTENDED)
        _unlock(uds_bus, 1, aes_keys)
        pdu = uds_bus.request(
            bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x87]) + bytes([0x41] * 5)
        )
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_INCORRECT_MSG_LEN, (
            f"Short WDBI payload must return NRC 0x13, got 0x{pdu[2]:02X}"
        )

    def test_wdbi_wrong_data_length_long(
        self, uds_bus: IsoTpTransport, aes_keys: dict
    ) -> None:
        """
        DID 0xF187 expects 11 bytes — sending 20 must return NRC 0x13.
        """
        _session(uds_bus, SESSION_EXTENDED)
        _unlock(uds_bus, 1, aes_keys)
        pdu = uds_bus.request(
            bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x87]) + bytes([0x41] * 20)
        )
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_INCORRECT_MSG_LEN

    def test_wdbi_no_did_bytes_rejected(self, uds_bus: IsoTpTransport) -> None:
        """[0x2E] only — no DID → NRC 0x13."""
        pdu = uds_bus.request(bytes([SID_WRITE_DATA_BY_ID]))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_INCORRECT_MSG_LEN

    def test_wdbi_unknown_did_rejected(self, uds_bus: IsoTpTransport) -> None:
        """Unknown DID 0xBEEF → NRC 0x31 (requestOutOfRange)."""
        _session(uds_bus, SESSION_EXTENDED)
        pdu = uds_bus.request(bytes([SID_WRITE_DATA_BY_ID, 0xBE, 0xEF, 0x00]))
        assert pdu is not None
        assert pdu[0] == SID_NEGATIVE_RESPONSE
        assert pdu[2] == NRC_REQUEST_OUT_OF_RANGE

    def test_write_then_read_back_f187(
        self, uds_bus: IsoTpTransport, aes_keys: dict
    ) -> None:
        """
        Write to 0xF187 then read it back — data must be persisted within the session.
        """
        _session(uds_bus, SESSION_EXTENDED)
        _unlock(uds_bus, 1, aes_keys)

        payload = bytes([0x58, 0x59, 0x5A, 0x31, 0x2E, 0x30, 0x20, 0x20, 0x20, 0x20, 0x20])
        assert len(payload) == 11

        wr = uds_bus.request(bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x87]) + payload)
        assert wr is not None and wr[0] == 0x6E

        rd = uds_bus.request(bytes([SID_READ_DATA_BY_ID, 0xF1, 0x87]))
        assert rd is not None
        # F187 requires extended session and security for read too
        if rd[0] == SID_NEGATIVE_RESPONSE:
            pytest.skip(f"Read-back not possible (NRC 0x{rd[2]:02X}) — read_sec gate")
        assert rd[0] == 0x62
        assert rd[3:] == payload, (
            f"Read-back data mismatch: wrote {payload.hex()}, got {rd[3:].hex()}"
        )


# ===========================================================================
# F. ISO-TP explicit multi-frame round-trip
# ===========================================================================

class TestIsoTpMultiFrameExplicit:
    """
    Explicit validation that the ISO-TP layer handles large payloads correctly.
    VIN (17 bytes) requires a multi-frame response (FF + CF).
    """

    def test_vin_read_returns_17_data_bytes(self, uds_bus: IsoTpTransport) -> None:
        """
        ReadDataByIdentifier 0xF190 (VIN) → response payload must be exactly
        1 (RSID) + 2 (DID) + 17 (VIN) = 20 bytes. Requires FF+CF from ECU.
        """
        pdu = uds_bus.request(bytes([SID_READ_DATA_BY_ID, 0xF1, 0x90]))
        assert pdu is not None
        assert pdu[0] == (SID_READ_DATA_BY_ID + POSITIVE_RESPONSE_OFFSET)
        assert pdu[1:3] == bytes([0xF1, 0x90]), "DID echo wrong in VIN response"
        vin_data = pdu[3:]
        assert len(vin_data) == 17, (
            f"VIN must be 17 bytes (ISO 3779), got {len(vin_data)}"
        )

    def test_multi_did_produces_large_response(self, uds_bus: IsoTpTransport) -> None:
        """
        VIN (17 bytes) + PartNum (11 bytes) via separate reads — each requires
        multi-frame response. Validates consecutive large-response handling.
        """
        pdu_vin = uds_bus.request(bytes([SID_READ_DATA_BY_ID, 0xF1, 0x90]))
        assert pdu_vin is not None and len(pdu_vin) == 20

        # F187 needs extended session
        _session(uds_bus, SESSION_EXTENDED)
        pdu_part = uds_bus.request(bytes([SID_READ_DATA_BY_ID, 0xF1, 0x87]))
        assert pdu_part is not None
        if pdu_part[0] != SID_NEGATIVE_RESPONSE:
            assert len(pdu_part) == 1 + 2 + 11   # RSID + DID + 11 bytes data


# ===========================================================================
# G. ClearDiagnosticInformation
# ===========================================================================

class TestClearDiagnosticInformation:
    """
    SID 0x14 — positive response, idempotent, no side-effects on session.
    """

    def test_clear_dtc_returns_positive_response(
        self, uds_bus: IsoTpTransport
    ) -> None:
        """[0x14, 0xFF, 0xFF, 0xFF] → [0x54]."""
        pdu = uds_bus.request(bytes([0x14, 0xFF, 0xFF, 0xFF]))
        assert pdu is not None
        assert pdu[0] == 0x54, (
            f"ClearDTC must return [0x54], got {pdu.hex(' ')}"
        )

    def test_clear_dtc_idempotent(self, uds_bus: IsoTpTransport) -> None:
        """Calling ClearDTC twice must return [0x54] both times."""
        pdu1 = uds_bus.request(bytes([0x14, 0xFF, 0xFF, 0xFF]))
        pdu2 = uds_bus.request(bytes([0x14, 0xFF, 0xFF, 0xFF]))
        assert pdu1 is not None and pdu1[0] == 0x54
        assert pdu2 is not None and pdu2[0] == 0x54

    def test_clear_does_not_change_session(self, uds_bus: IsoTpTransport) -> None:
        """
        ClearDTC must not change the active session.
        Enter Extended → ClearDTC → TesterPresent must still work.
        """
        _session(uds_bus, SESSION_EXTENDED)
        uds_bus.request(bytes([0x14, 0xFF, 0xFF, 0xFF]))
        pdu = uds_bus.request(bytes([SID_TESTER_PRESENT, 0x00]))
        assert pdu is not None
        assert pdu[0] == (SID_TESTER_PRESENT + POSITIVE_RESPONSE_OFFSET), (
            "ClearDTC must not change session — TesterPresent must still respond"
        )

    def test_sub02_after_clear_returns_empty_list(
        self, uds_bus: IsoTpTransport
    ) -> None:
        """
        After ClearDTC, all DTC statuses are 0x00.
        sub=0x02, mask=0xFF: (0x00 & 0xFF) = 0 → empty DTC list.
        This test mirrors TestDTCStatusMaskFiltering.test_sub02_mask_0xff but
        explicitly runs ClearDTC first to make the state explicit.
        """
        uds_bus.request(bytes([0x14, 0xFF, 0xFF, 0xFF]))
        pdu = uds_bus.request(bytes([SID_READ_DTC_INFO, 0x02, 0xFF]))
        assert pdu is not None
        assert pdu[0] == (SID_READ_DTC_INFO + POSITIVE_RESPONSE_OFFSET)
        dtc_section = pdu[3:]
        assert len(dtc_section) == 0, (
            f"After ClearDTC, sub=0x02 mask=0xFF must return 0 DTC entries, "
            f"got {len(dtc_section) // 4}: {pdu.hex(' ')}"
        )
